@namespace Lumeo
@implements IAsyncDisposable

@{
    var context = new ColorPickerContext(Value ?? "#000000", Open,
        EventCallback.Factory.Create<string>(this, OnColorChanged),
        EventCallback.Factory.Create<bool>(this, SetOpen),
        _wrapperId);
}

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null && !InsideFormField)
{
    <label class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<CascadingValue Value="context" IsFixed="false">
    <div id="@_wrapperId" class="@ContainerClass" @attributes="AdditionalAttributes">
        <button type="button"
                id="@FormFieldControlId"
                name="@Name"
                aria-required="@Required.ToString().ToLower()"
                aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                aria-describedby="@FormFieldDescribedBy"
                aria-haspopup="dialog"
                aria-expanded="@Open.ToString().ToLower()"
                aria-controls="@(Open ? _contentId : null)"
                class="@TriggerClass"
                @onclick="ToggleOpen"
                disabled="@Disabled"
                aria-label="@L["ColorPicker.PickColor"]">
            <span class="lumeo-cp-chip h-5 w-5 rounded-sm border border-border/40 shrink-0" style="@ChipStyle"></span>
            <span class="text-sm text-foreground font-mono">@DisplayHexField</span>
            <SvgGlyph Svg="@(LumeoIcons.ChevronDown)" class="@($"h-4 w-4 text-muted-foreground ms-auto transition-transform duration-200 {(Open ? "rotate-180" : "")}")" />
        </button>

        @if (Open)
        {
            <div id="@_contentId" class="@ContentClass" role="dialog" aria-label="@L["ColorPicker.PickColor"]"
                 @onkeydown="HandleKeyDown" tabindex="-1">

                @* Saturation-Value 2D picker *@
                <div id="@_svId"
                     class="lumeo-cp-sv relative w-full rounded-md overflow-hidden cursor-crosshair touch-none select-none focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                     style="@SvBackgroundStyle"
                     tabindex="0"
                     role="slider"
                     aria-label="@($"{L["ColorPicker.Saturation"]} / {L["ColorPicker.Value"]}")"
                     aria-valuemin="0"
                     aria-valuemax="100"
                     aria-valuenow="@_v"
                     aria-valuetext="@($"{L["ColorPicker.Saturation"]} {_s}%, {L["ColorPicker.Value"]} {_v}%")"
                     @onkeydown="HandleSvKeyDown">
                    @* Bug A — NOT a theme bug: rgba(255,255,255) white→transparent and rgba(0,0,0) black→transparent
                       are HSV color-space primitives (saturation and value axes). They are mathematically defined
                       constants for the SV canvas and must not use CSS theme variables. *@
                    <div class="absolute inset-0" style="background: linear-gradient(to right, rgba(255,255,255,1), rgba(255,255,255,0))"></div>
                    <div class="absolute inset-0" style="background: linear-gradient(to top, rgba(0,0,0,1), rgba(0,0,0,0))"></div>
                    @* Bug C — border-white is intentional (always-white circle contrasts against the colored SV canvas).
                       The outer shadow uses lumeo-cp-sv-indicator (CSS class) so it adapts to the page theme
                       via color-mix instead of being hardcoded rgba(0,0,0,0.35). *@
                    <div class="lumeo-cp-sv-indicator absolute h-4 w-4 -translate-x-1/2 -translate-y-1/2 rounded-full border-2 border-white pointer-events-none"
                         style="@SvIndicatorStyle"></div>
                </div>

                @* Hue slider *@
                <div class="mt-3">
                    <input type="range" min="0" max="360" value="@_h"
                           class="lumeo-cp-slider lumeo-cp-hue w-full cursor-pointer"
                           aria-label="@L["ColorPicker.Hue"]" aria-valuemin="0" aria-valuemax="360" aria-valuenow="@_h"
                           @oninput="OnHueChanged" />
                </div>

                @if (ShowAlpha)
                {
                    <div class="mt-2">
                        <input type="range" min="0" max="100" value="@_alpha"
                               class="lumeo-cp-slider lumeo-cp-slider-alpha w-full cursor-pointer"
                               style="--lumeo-cp-color: @SolidColorHex"
                               aria-label="@L["ColorPicker.Opacity"]" aria-valuemin="0" aria-valuemax="100" aria-valuenow="@_alpha"
                               @oninput="OnAlphaChanged" />
                    </div>
                }

                @* Preview + Hex *@
                <div class="mt-3 flex items-center gap-2">
                    <div class="lumeo-cp-chip h-9 w-9 rounded-md border border-border/40 shrink-0" style="@ChipStyle"></div>
                    <input type="text" value="@DisplayHexField"
                           class="flex h-9 w-full min-w-0 rounded-md border border-border/60 bg-transparent px-2 text-xs font-mono uppercase focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                           @onchange="OnHexInput" maxlength="9"
                           aria-label="@L["ColorPicker.HexValue"]" />
                </div>

                @* RGB inputs *@
                <div class="mt-2 grid grid-cols-3 gap-1.5">
                    <div>
                        <input type="number" min="0" max="255" value="@_r"
                               class="flex h-8 w-full min-w-0 rounded-md border border-border/60 bg-transparent px-1.5 text-xs font-mono tabular-nums text-center focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                               @onchange="OnRChanged" aria-label="@L["ColorPicker.Red"]" />
                        <div class="mt-0.5 text-[10px] text-muted-foreground text-center">R</div>
                    </div>
                    <div>
                        <input type="number" min="0" max="255" value="@_g"
                               class="flex h-8 w-full min-w-0 rounded-md border border-border/60 bg-transparent px-1.5 text-xs font-mono tabular-nums text-center focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                               @onchange="OnGChanged" aria-label="@L["ColorPicker.Green"]" />
                        <div class="mt-0.5 text-[10px] text-muted-foreground text-center">G</div>
                    </div>
                    <div>
                        <input type="number" min="0" max="255" value="@_b"
                               class="flex h-8 w-full min-w-0 rounded-md border border-border/60 bg-transparent px-1.5 text-xs font-mono tabular-nums text-center focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                               @onchange="OnBChanged" aria-label="@L["ColorPicker.Blue"]" />
                        <div class="mt-0.5 text-[10px] text-muted-foreground text-center">B</div>
                    </div>
                </div>

                @if (Presets is { Count: > 0 })
                {
                    <div class="mt-3 pt-3 border-t border-border/40">
                        <div class="flex flex-wrap gap-1.5">
                            @foreach (var preset in Presets)
                            {
                                <Tooltip>
                                    <TooltipTrigger AsChild>
                                        <ChildContentSlot Context="slot">
                                            <button type="button"
                                                    class="@GetSwatchClass()"
                                                    style="background-color: @preset"
                                                    @onclick="() => SelectColor(preset)"
                                                    aria-label="@preset"
                                                    @attributes="slot.Attributes">
                                                @if (string.Equals(Value, preset, StringComparison.OrdinalIgnoreCase))
                                                {
                                                    <SvgGlyph Svg="@(LumeoIcons.Check)" class="@CheckIconClass(preset)" />
                                                }
                                            </button>
                                        </ChildContentSlot>
                                    </TooltipTrigger>
                                    <TooltipContent>@preset</TooltipContent>
                                </Tooltip>
                            }
                        </div>
                    </div>
                }
            </div>
        }
    </div>
</CascadingValue>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}
</div>

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    /// <summary>Marks the field as required, setting <c>aria-required</c> on the trigger button and (outside a <c>FormField</c>) appending a destructive-colored asterisk to the label.</summary>
    [Parameter] public bool Required { get; set; }

    /// <summary>Forces the invalid/error visual state (destructive border and focus ring) and <c>aria-invalid</c>, independent of the ambient <c>FormField</c>'s validation state.</summary>
    [Parameter] public bool Invalid { get; set; }

    /// <summary>Error message shown below the trigger (outside a <c>FormField</c>) when <see cref="Invalid"/> is set. Takes precedence over <see cref="HelperText"/>.</summary>
    [Parameter] public string? ErrorText { get; set; }

    /// <summary>Helper text shown below the trigger (outside a <c>FormField</c>) when there is no error to display.</summary>
    [Parameter] public string? HelperText { get; set; }

    /// <summary>Label text rendered above the trigger (outside a <c>FormField</c>, which supplies its own label).</summary>
    [Parameter] public string? Label { get; set; }

    /// <summary>HTML <c>name</c> attribute applied to the trigger button, used when the picker participates in native form submission.</summary>
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    /// <summary>The selected color, as a hex string (<c>#RGB</c>/<c>#RRGGBB</c>/<c>#RRGGBBAA</c>) or an <c>rgba(r, g, b, a)</c> string when the alpha slider has been used. Defaults to <c>#000000</c> when <see langword="null"/>.</summary>
    [Parameter] public string? Value { get; set; }

    /// <summary>Raised whenever the color changes, via the SV canvas, hue/alpha sliders, RGB inputs, hex field, or a preset swatch.</summary>
    [Parameter] public EventCallback<string> ValueChanged { get; set; }

    /// <summary>Shows the alpha (opacity) slider and emits an <c>rgba()</c> <see cref="Value"/> whenever alpha drops below 100%.</summary>
    [Parameter] public bool ShowAlpha { get; set; }

    /// <summary>Optional palette of hex colors rendered as clickable swatches below the RGB inputs.</summary>
    [Parameter] public List<string>? Presets { get; set; }

    /// <summary>Disables the trigger button, preventing the popover from opening.</summary>
    [Parameter] public bool Disabled { get; set; }

    /// <summary>Whether the picker popover is open. Two-way bindable via <see cref="OpenChanged"/>.</summary>
    [Parameter] public bool Open { get; set; }

    /// <summary>Raised when the popover's open state changes, e.g. via the trigger, Escape, or an outside click.</summary>
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>Legacy alias for <see cref="Open"/>.</summary>
    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    /// <summary>Legacy alias for <see cref="OpenChanged"/>.</summary>
    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    /// <summary>Additional CSS classes merged onto the picker's outer wrapper.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the picker's outer wrapper.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _wrapperId = LumeoIds.New("colorpicker");
    private readonly string _contentId = LumeoIds.New("colorpicker-content");
    private readonly string _svId = LumeoIds.New("colorpicker-sv");
    private bool _registered;

    private int _h;
    private int _s = 100;
    private int _v = 100;
    private int _alpha = 100;
    private int _r, _g, _b;
    private string? _lastSyncedValue;

    private string ContainerClass => Cx.Merge("relative inline-block", Class);

    private string TriggerClass => $"flex items-center gap-2 h-9 px-3 rounded-md border {(EffectiveInvalid ? "border-destructive ring-1 ring-destructive/20" : "border-border/60")} bg-background text-sm hover:bg-accent hover:text-accent-foreground transition-colors disabled:cursor-not-allowed disabled:opacity-50 focus-visible:outline-none focus-visible:ring-[1.5px] {(EffectiveInvalid ? "focus-visible:ring-destructive" : "focus-visible:ring-ring")}";

    private const string ContentClass = "fixed z-50 w-72 rounded-md border border-border/40 bg-popover p-3 text-popover-foreground shadow-lg animate-fade-in";

    private string ChipStyle => $"background-color: {DisplayColor}";
    private string DisplayColor => ShowAlpha && _alpha < 100
        ? $"rgba({_r}, {_g}, {_b}, {(_alpha / 100.0).ToString("0.##", System.Globalization.CultureInfo.InvariantCulture)})"
        : SolidColorHex;
    private string SolidColorHex => $"#{_r:X2}{_g:X2}{_b:X2}";

    // Battle-wave2 #27 (medium, edge-data) — the hex <input> and trigger
    // caption previously rendered the raw bound Value, which is an rgba(...)
    // string whenever ShowAlpha is on and alpha is below 100. Dumping that
    // rgba string into the *hex* <input> rendered nonsense AND got silently
    // chopped by the input's maxlength="9" (e.g. "rgba(255, 0, 0, 0.5)" →
    // "rgba(255,"). DisplayHexField always projects a real hex: #RRGGBBAA when
    // alpha is partial (exactly 9 chars, so it fits maxlength="9" and
    // round-trips through OnHexInput/SyncStateFromHex, which already accept
    // length-9 hex), otherwise the compact #RRGGBB.
    private string DisplayHexField => ShowAlpha && _alpha < 100
        ? $"#{_r:X2}{_g:X2}{_b:X2}{(int)Math.Round(_alpha / 100.0 * 255):X2}"
        : SolidColorHex;

    private string SvBackgroundStyle => $"background-color: hsl({_h}, 100%, 50%)";
    private string SvIndicatorStyle => $"left: {_s.ToString(System.Globalization.CultureInfo.InvariantCulture)}%; top: {(100 - _v).ToString(System.Globalization.CultureInfo.InvariantCulture)}%";

    private static string GetSwatchClass() =>
        "h-6 w-6 rounded-sm border border-border/40 cursor-pointer hover:scale-110 transition-transform flex items-center justify-center focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring";

    // Bug B — NOT a theme bug: text-black / text-white here is contrast-against-the-swatch-color, not against the
    // page background. The luminance check picks whichever extreme (black or white) is most readable on top of the
    // specific preset swatch. This is correct regardless of the page's light/dark theme.
    private static string CheckIconClass(string color) =>
        $"h-3 w-3 {(IsLight(color) ? "text-black" : "text-white")} drop-shadow-[0_1px_1px_rgba(0,0,0,0.35)]";

    protected override void OnParametersSet()
    {
        var current = Value ?? "#000000";
        // Battle-wave2 #147 (low, state-on-data-change) — compare colours by
        // PARSED equivalence, not by raw string. The parent often feeds the
        // value back in a different string form than the component emitted
        // (e.g. we emit "rgba(255, 0, 0, 0.5)" with spaces but a normalising
        // consumer pushes back "rgba(255,0,0,0.5)" or "#FF000080", or hands us
        // "rgb(255,255,255)" for our "#FFFFFF"). An OrdinalIgnoreCase string
        // compare treats those as a real change and re-runs SyncStateFromHex,
        // whose RgbToHsv re-derivation can JUMP the in-progress hue / SV
        // position (hue is ambiguous for achromatic colours, so a hue picked
        // on white snaps back to 0). Skip the re-sync whenever the incoming
        // colour resolves to the RGB(+alpha) we already hold so _h/_s/_v are
        // preserved; only re-sync on a genuinely different colour.
        if (string.Equals(current, _lastSyncedValue, StringComparison.OrdinalIgnoreCase))
        {
            return;
        }

        if (TryParseColor(current, out var cr, out var cg, out var cb, out var ca)
            && cr == _r && cg == _g && cb == _b && (!ShowAlpha || ca == _alpha))
        {
            // Same colour, different string form — adopt the new canonical
            // string but keep the existing _h/_s/_v so the picker doesn't jump.
            _lastSyncedValue = current;
            return;
        }

        SyncStateFromHex(current);
        _lastSyncedValue = current;
    }

    // Parses either hex (#RGB / #RRGGBB / #RRGGBBAA) or rgb()/rgba() into
    // r/g/b plus an alpha percentage. Plain hex / rgb() report alpha as 100.
    private static bool TryParseColor(string value, out int r, out int g, out int b, out int alphaPct)
    {
        if (TryParseHex(value, out r, out g, out b))
        {
            alphaPct = 100;
            if (value.Length == 9 && int.TryParse(value.AsSpan(7, 2), System.Globalization.NumberStyles.HexNumber, null, out var ah))
            {
                alphaPct = (int)Math.Round(ah / 255.0 * 100.0);
            }
            return true;
        }
        return TryParseRgba(value, out r, out g, out b, out alphaPct);
    }

    private async Task ToggleOpen() { if (!Disabled) await SetOpen(!Open); }

    private async Task SetOpen(bool value)
    {
        Open = value;
        await OpenChanged.InvokeAsync(value);
    }

    private async Task SelectColor(string color) => await ApplyColor(color);

    private async Task OnColorChanged(string color) => await ApplyColor(color);

    private async Task ApplyColor(string color)
    {
        Value = color;
        SyncStateFromHex(color);
        _lastSyncedValue = color;
        await ValueChanged.InvokeAsync(color);
    }

    private async Task OnHueChanged(ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var h))
        {
            _h = Math.Clamp(h, 0, 360);
            await ApplyHsv();
        }
    }

    private async Task OnAlphaChanged(ChangeEventArgs e)
    {
        if (!int.TryParse(e.Value?.ToString(), out var a)) return;
        _alpha = Math.Clamp(a, 0, 100);
        await ApplyAlpha();
    }

    private async Task OnRChanged(ChangeEventArgs e) { if (int.TryParse(e.Value?.ToString(), out var n)) { _r = Math.Clamp(n, 0, 255); await ApplyRgb(); } }
    private async Task OnGChanged(ChangeEventArgs e) { if (int.TryParse(e.Value?.ToString(), out var n)) { _g = Math.Clamp(n, 0, 255); await ApplyRgb(); } }
    private async Task OnBChanged(ChangeEventArgs e) { if (int.TryParse(e.Value?.ToString(), out var n)) { _b = Math.Clamp(n, 0, 255); await ApplyRgb(); } }

    // Single point of truth for the bound Value string. When alpha is at
    // 100 % (or alpha is disabled), emit the compact hex form so existing
    // consumers that only handle hex keep working. Below 100 %, emit
    // rgba() so the alpha is actually round-trippable to CSS.
    private string ComposeCurrentValue() =>
        ShowAlpha && _alpha < 100
            ? $"rgba({_r}, {_g}, {_b}, {(_alpha / 100.0).ToString("0.##", System.Globalization.CultureInfo.InvariantCulture)})"
            : $"#{_r:X2}{_g:X2}{_b:X2}";

    private async Task ApplyHsv()
    {
        (_r, _g, _b) = HsvToRgb(_h, _s, _v);
        Value = ComposeCurrentValue();
        _lastSyncedValue = Value;
        await ValueChanged.InvokeAsync(Value);
    }

    private async Task ApplyRgb()
    {
        Value = ComposeCurrentValue();
        (_h, _s, _v) = RgbToHsv(_r, _g, _b);
        _lastSyncedValue = Value;
        await ValueChanged.InvokeAsync(Value);
    }

    private async Task ApplyAlpha()
    {
        Value = ComposeCurrentValue();
        _lastSyncedValue = Value;
        await ValueChanged.InvokeAsync(Value);
    }

    private async Task OnHexInput(ChangeEventArgs e)
    {
        var hex = e.Value?.ToString()?.Trim() ?? "";
        if (!hex.StartsWith('#')) hex = "#" + hex;
        if (hex.Length is 4 or 7 or 9 && IsValidHex(hex))
        {
            await ApplyColor(hex);
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape") await SetOpen(false);
    }

    // The Saturation/Value canvas is a pointer-drag surface (RegisterSvDrag),
    // which is mouse-only — keyboard users could never reach the inner 2D
    // axis (WCAG 2.1.1). The div is now a focusable role="slider": Arrow
    // Left/Right walk saturation (X), Arrow Up/Down walk value (Y), Shift
    // multiplies the step by 10, and Home/End clamp the focused axis. This
    // mirrors the keyboard travel the native hue/alpha range inputs already
    // provide. The page-scroll default for these keys is suppressed via the
    // RegisterPreventDefaultKeys interop (see OnAfterRenderAsync) so Tab still
    // moves focus out of the canvas normally.
    private async Task HandleSvKeyDown(KeyboardEventArgs e)
    {
        var step = e.ShiftKey ? 10 : 1;
        int newS = _s, newV = _v;

        switch (e.Key)
        {
            case "ArrowLeft":  newS = Math.Clamp(_s - step, 0, 100); break;
            case "ArrowRight": newS = Math.Clamp(_s + step, 0, 100); break;
            case "ArrowDown":  newV = Math.Clamp(_v - step, 0, 100); break;
            case "ArrowUp":    newV = Math.Clamp(_v + step, 0, 100); break;
            case "Home":       newS = 0;   break;
            case "End":        newS = 100; break;
            case "PageDown":   newV = 0;   break;
            case "PageUp":     newV = 100; break;
            default: return;
        }

        if (newS == _s && newV == _v) return;
        _s = newS;
        _v = newV;
        await ApplyHsv();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Open && !_registered)
        {
            await Interop.PositionFixed(_contentId, _wrapperId, "start", false, "bottom");
            await Interop.RegisterClickOutside(_contentId, _wrapperId, async () =>
            {
                await SetOpen(false);
                await InvokeAsync(StateHasChanged);
            });
            await Interop.RegisterSvDrag(_svId, async (s, v) =>
            {
                _s = (int)Math.Round(Math.Clamp(s, 0, 100));
                _v = (int)Math.Round(Math.Clamp(v, 0, 100));
                await ApplyHsv();
                await InvokeAsync(StateHasChanged);
            });
            // The arrow / Home / End / PageUp / PageDown keys drive the SV
            // canvas (HandleSvKeyDown); suppress their native page-scroll so
            // the focused picker doesn't scroll the page out from under the
            // user. Tab is deliberately NOT in the list so focus can still
            // leave the canvas. Mirrors the Rating component's a11y pattern.
            try
            {
                await Interop.RegisterPreventDefaultKeys(
                    _svId,
                    new[] { "ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft", "Home", "End", "PageUp", "PageDown" }
                        .Select(k => new Lumeo.Services.PreventDefaultKeyRule(k)).ToArray());
            }
            catch (JSDisconnectedException) { }
            // Focus management (#191) — mirror the Popover Wave-1 fix. The trap
            // moves focus into the popover on open (so the content's @onkeydown
            // Escape handler is reachable WITHOUT a preliminary click), cycles
            // Tab among the picker's controls, and restores focus to the trigger
            // button on close (WCAG 2.4.3).
            try { await Interop.SetupFocusTrap(_contentId); } catch (JSDisconnectedException) { }
            _registered = true;
        }
        else if (!Open && _registered)
        {
            await Cleanup();
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterSvDrag(_svId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterPreventDefaultKeys(_svId); } catch (JSDisconnectedException) { }
        try { await Interop.RemoveFocusTrap(_contentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }

    // Parses both hex (#RGB / #RRGGBB / #RRGGBBAA) and rgba(r,g,b[,a]) into
    // the component's r/g/b/h/s/v/alpha state. Without rgba() handling, a
    // saved Value emitted by the alpha slider (which writes 'rgba(...)' when
    // ShowAlpha + alpha<100) couldn't round-trip on remount — the trigger
    // text showed the rgba string while the internal state fell back to
    // black/100%, so the preview and the next slider edit corrupted the
    // saved color (Codex #78 review).
    private void SyncStateFromHex(string value)
    {
        if (TryParseHex(value, out var hr, out var hg, out var hb))
        {
            _r = hr; _g = hg; _b = hb;
            (_h, _s, _v) = RgbToHsv(_r, _g, _b);
            // Hex with alpha pair (#RRGGBBAA) updates alpha; plain hex
            // leaves the existing _alpha untouched so a consumer toggling
            // between hex strings doesn't reset the slider.
            if (value.Length == 9 && int.TryParse(value.AsSpan(7, 2), System.Globalization.NumberStyles.HexNumber, null, out var ah))
            {
                _alpha = (int)Math.Round(ah / 255.0 * 100.0);
            }
            return;
        }

        if (TryParseRgba(value, out var rr, out var rg, out var rb, out var ra))
        {
            _r = rr; _g = rg; _b = rb;
            (_h, _s, _v) = RgbToHsv(_r, _g, _b);
            _alpha = ra;
        }
    }

    // Accepts 'rgba(r,g,b[,a])' / 'rgb(r,g,b)' with whitespace tolerance.
    // Alpha is the 0.0–1.0 CSS form; we convert to 0–100 to match the
    // component's internal scale.
    private static bool TryParseRgba(string value, out int r, out int g, out int b, out int alphaPct)
    {
        r = g = b = 0;
        alphaPct = 100;
        if (string.IsNullOrEmpty(value)) return false;
        var open = value.IndexOf('(');
        var close = value.IndexOf(')');
        if (open <= 0 || close <= open) return false;
        var prefix = value[..open].Trim().ToLowerInvariant();
        if (prefix != "rgb" && prefix != "rgba") return false;

        var parts = value[(open + 1)..close].Split(',');
        if (parts.Length < 3 || parts.Length > 4) return false;

        if (!int.TryParse(parts[0].Trim(), System.Globalization.NumberStyles.Integer, System.Globalization.CultureInfo.InvariantCulture, out r)) return false;
        if (!int.TryParse(parts[1].Trim(), System.Globalization.NumberStyles.Integer, System.Globalization.CultureInfo.InvariantCulture, out g)) return false;
        if (!int.TryParse(parts[2].Trim(), System.Globalization.NumberStyles.Integer, System.Globalization.CultureInfo.InvariantCulture, out b)) return false;
        r = Math.Clamp(r, 0, 255);
        g = Math.Clamp(g, 0, 255);
        b = Math.Clamp(b, 0, 255);

        if (parts.Length == 4 && double.TryParse(parts[3].Trim(), System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture, out var a))
        {
            alphaPct = (int)Math.Round(Math.Clamp(a, 0.0, 1.0) * 100.0);
        }
        return true;
    }

    private static bool IsValidHex(string hex)
    {
        if (string.IsNullOrEmpty(hex) || hex[0] != '#') return false;
        if (hex.Length is not (4 or 7 or 9)) return false;
        for (int i = 1; i < hex.Length; i++)
            if (!Uri.IsHexDigit(hex[i])) return false;
        return true;
    }

    private static bool TryParseHex(string hex, out int r, out int g, out int b)
    {
        r = g = b = 0;
        if (!IsValidHex(hex)) return false;
        if (hex.Length == 4)
        {
            r = int.Parse($"{hex[1]}{hex[1]}", System.Globalization.NumberStyles.HexNumber);
            g = int.Parse($"{hex[2]}{hex[2]}", System.Globalization.NumberStyles.HexNumber);
            b = int.Parse($"{hex[3]}{hex[3]}", System.Globalization.NumberStyles.HexNumber);
        }
        else
        {
            r = int.Parse(hex.Substring(1, 2), System.Globalization.NumberStyles.HexNumber);
            g = int.Parse(hex.Substring(3, 2), System.Globalization.NumberStyles.HexNumber);
            b = int.Parse(hex.Substring(5, 2), System.Globalization.NumberStyles.HexNumber);
        }
        return true;
    }

    private static bool IsLight(string hex)
    {
        if (!TryParseHex(hex, out var r, out var g, out var b)) return false;
        var luminance = (0.299 * r + 0.587 * g + 0.114 * b) / 255.0;
        return luminance > 0.6;
    }

    private static (int r, int g, int b) HsvToRgb(int h, int s, int v)
    {
        double hd = h / 360.0;
        double sd = s / 100.0;
        double vd = v / 100.0;

        if (sd < 0.0001)
        {
            var n = (int)Math.Round(vd * 255);
            return (n, n, n);
        }

        double sector = hd * 6;
        int i = (int)Math.Floor(sector);
        double f = sector - i;
        double p = vd * (1 - sd);
        double q = vd * (1 - sd * f);
        double t = vd * (1 - sd * (1 - f));

        double r, g, b;
        switch (i % 6)
        {
            case 0: r = vd; g = t;  b = p;  break;
            case 1: r = q;  g = vd; b = p;  break;
            case 2: r = p;  g = vd; b = t;  break;
            case 3: r = p;  g = q;  b = vd; break;
            case 4: r = t;  g = p;  b = vd; break;
            default: r = vd; g = p; b = q;  break;
        }
        return ((int)Math.Round(r * 255), (int)Math.Round(g * 255), (int)Math.Round(b * 255));
    }

    private static (int h, int s, int v) RgbToHsv(int r, int g, int b)
    {
        double rd = r / 255.0, gd = g / 255.0, bd = b / 255.0;
        double max = Math.Max(rd, Math.Max(gd, bd));
        double min = Math.Min(rd, Math.Min(gd, bd));
        double d = max - min;

        double h = 0;
        if (d > 0.0001)
        {
            if (max == rd)      h = 60 * (((gd - bd) / d) % 6);
            else if (max == gd) h = 60 * ((bd - rd) / d + 2);
            else                h = 60 * ((rd - gd) / d + 4);
            if (h < 0) h += 360;
        }
        double s = max < 0.0001 ? 0 : d / max;
        double v = max;
        return ((int)Math.Round(h), (int)Math.Round(s * 100), (int)Math.Round(v * 100));
    }

